# rn与内嵌网页 用webView桥接
- 解决方案
在 `injectedJavaScript` 内事先添加对 `message` 的监听事件，
然后使用webView props属性 `onMessage` 和 实例方法 `postMessage` 进行一收一发。
需要注意的是，收发，都是收发字符串类型的数据，可以使用json字符串

```javascript
const renderChart = (props) => {
  const height = `${props.height || 400}px`;
  const width = props.width ? `${props.width}px` : 'auto';
  const backgroundColor = props.backgroundColor;
  return `
      document.getElementById('main').style.height = "${height}";
      document.getElementById('main').style.width = "${width}";
      document.getElementById('main').style.backgroundColor = "${backgroundColor}";
      var myChart = echarts.init(document.getElementById('main'));
      myChart.setOption(${JSON.stringify(props.option)});
      window.document.addEventListener('message', function(e) {
        var req = JSON.parse(e.data);
        switch (req.types) {
          case "SET_OPTION":
            myChart.setOption(req.payload.option,req.payload.notMerge,req.payload.lazyUpate);
            break;
          case "GET_IMAGE":
            var base64 = myChart.getDataURL();
            window.postMessage(JSON.stringify({"types":"GET_IMAGE","payload": base64}));
            break;
          case "CLEAR":
            myChart.clear();
            break;
          default:
            break;
        }
      });
      myChart.on('click', function(params) {
        var seen = [];
        var paramsString = JSON.stringify(params, function(key, val) {
          if (val != null && typeof val == "object") {
            if (seen.indexOf(val) >= 0) {
              return;
            }
            seen.push(val);
          }
          return val;
        });
        window.postMessage(JSON.stringify({"types":"ON_PRESS","payload": paramsString}));
      });
    `
}

export default renderChart;
```


```javascript
class Echarts extends Component {
  ...

  render() {
    ...
    return (
      <View style={{flexDirection: 'row',width: this.props.width}}>
        <View style={{flex:1,height: this.props.height || 400}}>
          <WebView
            ref="chart"
            ...
            onMessage={this._handleMessage}
            injectedJavaScript={renderChart(this.props)}
            ...
          />
        </View>
      </View>
    );
  }

  _handleMessage = (e) => {
    if (!e) return null;
    const data = JSON.parse(e.nativeEvent.data)
    switch (data.types) {
      case 'ON_PRESS':
        this.props.onPress(JSON.parse(data.payload))
        break;
      case 'GET_IMAGE':
        this.setState({data})
        break;
      default:
        break;
    }
  };

  _postMessage(data){
    this.refs.chart.postMessage(JSON.stringify(data));
  }

  setOption = (option,notMerge, lazyUpdate) => {
    let data = {
      types: 'SET_OPTION',
      payload: {
        option:option,
        notMerge:notMerge || false,
        lazyUpdate:lazyUpdate || false
      }
    }
    this._postMessage(data);
  }

  clear=()=>{
    let data = {
      types: 'CLEAR'
    }
    this._postMessage(data);
  }

  getImage = (callback) => {
    let data = {
      types: 'GET_IMAGE',
      payload: null
    }
    this._postMessage(data);
    setTimeout(() => {
      if(this.state.data.types === 'GET_IMAGE') {
        callback(this.state.data)
      } else {
        callback(null)
      }
    }, 500);
  }  
}
```

# postMessage 传递对象 JSON.stringify 后函数对象变为空字符串
- 解决方案
对function进行特殊处理
```javascript
const toString = (obj) => {
  let result = JSON.stringify(obj, function(key, val) {
        // 对function进行特殊处理
        if (typeof val === 'function') {
            return `~ha~${val}~ha~`;
        }
        return val;
    });
    // 再进行还原
    do {
        result = result.replace('\"~ha~', '').replace('~ha~\"', '').replace(/\\n/g, '').replace(/\\\"/g,"\"");//最后一个replace将release模式中莫名生成的\"转换成"
    } while (result.indexOf('~ha~') >= 0);
    return result;
}
const renderChart = (props) => {
  const height = `${props.height || 400}px`;
  const width = props.width ? `${props.width}px` : 'auto';
  const backgroundColor = props.backgroundColor;
  return `
      document.getElementById('main').style.height = "${height}";
      document.getElementById('main').style.width = "${width}";
      document.getElementById('main').style.backgroundColor = "${backgroundColor}";
      var myChart = echarts.init(document.getElementById('main'));
      myChart.setOption(${toString(props.option)});
      window.document.addEventListener('message', function(e) {
        var req = JSON.parse(e.data);
        switch (req.types) {
          case "SET_OPTION":
            myChart.setOption(req.payload.option,req.payload.notMerge,req.payload.lazyUpate);
            break;
          case "GET_IMAGE":
            var base64 = myChart.getDataURL();
            window.postMessage(JSON.stringify({"types":"GET_IMAGE","payload": base64}));
            break;
          case "CLEAR":
            myChart.clear();
            break;
          default:
            break;
        }
      });
      myChart.on('click', function(params) {
        var seen = [];
        var paramsString = JSON.stringify(params, function(key, val) {
          if (val != null && typeof val == "object") {
            if (seen.indexOf(val) >= 0) {
              return;
            }
            seen.push(val);
          }
          return val;
        });
        window.postMessage(JSON.stringify({"types":"ON_PRESS","payload": paramsString}));
      });
    `
}

export default renderChart;
```

在我们公司rn的项目中，使用的是 `react-native-splash-screen` 这个启动屏组件。

但是在实际使用过程中，会发现android下的启动屏幕是没有固定比例的，组件官方给出的解决方案是使用线性布局。

代码如下：
```xml
<?xml version="1.0" encoding="utf-8"?>
<LinearLayout xmlns:android="http://schemas.android.com/apk/res/android"
    android:orientation="vertical" android:layout_width="match_parent"
    android:layout_height="match_parent"
    android:background="@drawable/launch_screen">
</LinearLayout>
```

由于是线性布局，这样写会出现一个图片宽度或者高度被拉伸的情况，我们程序员肉眼凡胎看不出来，但是像素眼的美工一眼就看出来了，如下图：

<img src="./pic1.png" style="width:400px;" title="线性布局"/>

---------------------------------

没办法，本着尊重设计的原则，我们下来就换成了 `ImageView` 并使用 `android:scaleType="centerCrop"` 属性来保证图片宽度或者高度不被拉伸。

代码如下：
```xml
<?xml version="1.0" encoding="utf-8"?>
<ImageView xmlns:android="http://schemas.android.com/apk/res/android"
    android:layout_width="match_parent"
    android:layout_height="match_parent"
    android:orientation="vertical"
    android:scaleType="centerCrop"
    android:src="@drawable/launch_screen">
</ImageView>
```

这样写固然好，在美工16:9的机器上面表现完美，但是在我的测试机上却出现了只能适配16:9的问题，如下图：

<img src="./pic2.png" style="width:400px;" title="ImageView 的 centerCrop"/>

---------------------------------

无奈只好另寻方法。

突然灵光一闪，能不能自己用 `matrix` 实现一个 TopCrop 或者 bottomCrop 呢。于是google了一下，还真的有解决方案。

---------------------------------

先写了一下TopCrop的

图片会铺满左右宽度，并且顶到容器顶部，图片底部多于容器高度的部分会被剪裁掉。

代码如下：

```java
package com.sicap;

import android.content.Context;
import android.graphics.Matrix;
import android.util.AttributeSet;
import android.widget.ImageView;

public class TopCropImageView extends ImageView {
    public TopCropImageView(Context context, AttributeSet attrs) {
        super(context, attrs);
        setScaleType(ScaleType.MATRIX);
    }

    public TopCropImageView(Context context, AttributeSet attrs, int defStyle) {
        super(context, attrs, defStyle);
        setScaleType(ScaleType.MATRIX);
    }

    public TopCropImageView(Context context) {
        super(context);
        setScaleType(ScaleType.MATRIX);
    }

    @Override
    protected boolean setFrame(int l, int t, int r, int b) {
        if (getDrawable() == null) {
            return super.setFrame(l, t, r, b);
        }
        Matrix matrix = getImageMatrix();
        float scaleWidth = getWidth() / (float) getDrawable().getIntrinsicWidth();
        float scaleHeight = getHeight() / (float) getDrawable().getIntrinsicHeight();
        float scaleFactor = (scaleWidth > scaleHeight) ? scaleWidth : scaleHeight;
        matrix.setScale(scaleFactor, scaleFactor, 0, 0);
        if (scaleFactor == scaleHeight) {
            float tanslateX = ((getDrawable().getIntrinsicWidth() * scaleFactor) - getWidth()) / 2;
            matrix.postTranslate(-tanslateX, 0);
        }
        setImageMatrix(matrix);
        return super.setFrame(l, t, r, b);
    }

}
```

```xml
<?xml version="1.0" encoding="utf-8"?>
<com.sicap.TopCropImageView xmlns:android="http://schemas.android.com/apk/res/android"
    android:layout_width="match_parent"
    android:layout_height="match_parent"
    android:orientation="vertical"
    android:src="@drawable/launch_screen">

</com.sicap.TopCropImageView>
```

